"""Onboarding status, AWS setup guide, and user activation."""

from __future__ import annotations

from dataclasses import dataclass
from datetime import datetime
from typing import Any
from uuid import UUID

from sqlalchemy.ext.asyncio import AsyncSession

from backtrace_agent.config import settings
from backtrace_agent.db.models import User, UserAwsConnection, UserDetectionConfig, UserStatus
from backtrace_agent.db.repositories import (
    UserAwsConnectionRepository,
    UserDetectionConfigRepository,
    UserRepository,
)
from backtrace_agent.onboarding.aws_connection import parse_role_account_id


@dataclass(frozen=True, slots=True)
class OnboardingSteps:
    aws_connection_saved: bool
    aws_connection_verified: bool
    detection_config_saved: bool
    monitoring_active: bool


def _aws_connection_saved(conn: UserAwsConnection | None) -> bool:
    if conn is None:
        return False
    return bool(conn.aws_region and conn.log_group_name and conn.role_arn)


def compute_steps(
    user: User,
    aws_connection: UserAwsConnection | None,
    detection_config: UserDetectionConfig | None,
) -> OnboardingSteps:
    return OnboardingSteps(
        aws_connection_saved=_aws_connection_saved(aws_connection),
        aws_connection_verified=bool(
            aws_connection and aws_connection.connection_verified_at
        ),
        detection_config_saved=detection_config is not None,
        monitoring_active=user.status == UserStatus.ACTIVE.value,
    )


def is_onboarding_complete(
    user: User,
    aws_connection: UserAwsConnection | None,
    detection_config: UserDetectionConfig | None,
) -> bool:
    if user.status == UserStatus.ACTIVE.value:
        return True
    steps = compute_steps(user, aws_connection, detection_config)
    return (
        steps.aws_connection_verified
        and steps.detection_config_saved
    )


def activation_missing_steps(
    user: User,
    aws_connection: UserAwsConnection | None,
    detection_config: UserDetectionConfig | None,
) -> list[str]:
    steps = compute_steps(user, aws_connection, detection_config)
    missing: list[str] = []
    if not steps.aws_connection_saved:
        missing.append("aws_connection_saved")
    if not steps.aws_connection_verified:
        missing.append("aws_connection_verified")
    if not steps.detection_config_saved:
        missing.append("detection_config_saved")
    return missing


def detection_config_to_api(
    row: UserDetectionConfig | None,
) -> dict[str, Any]:
    if row is None:
        return {
            "error_filter_field": settings.error_filter_field,
            "error_filter_values": list(settings.error_filter_values),
            "lifecycle_window_minutes": settings.lifecycle_window_minutes,
            "anchor_patterns": list(settings.anchor_patterns),
            "custom_grok_patterns": list(settings.custom_grok_patterns),
            "actionable_severities": list(settings.actionable_severities),
        }
    return {
        "error_filter_field": row.error_filter_field,
        "error_filter_values": list(row.error_filter_values),
        "lifecycle_window_minutes": row.lifecycle_window_minutes,
        "anchor_patterns": list(row.anchor_patterns or []),
        "custom_grok_patterns": list(row.custom_grok_patterns or []),
        "actionable_severities": (
            list(row.actionable_severities)
            if row.actionable_severities is not None
            else None
        ),
    }


def aws_connection_to_api(conn: UserAwsConnection | None) -> dict[str, Any] | None:
    if conn is None or not _aws_connection_saved(conn):
        return None
    return {
        "aws_region": conn.aws_region,
        "log_group_name": conn.log_group_name,
        "role_arn": conn.role_arn,
        "connection_verified_at": conn.connection_verified_at,
        "last_connection_error": conn.last_connection_error,
        "last_connection_test_at": conn.last_connection_test_at,
    }


def build_trust_policy_template(*, platform_account_id: str, external_id: str) -> dict[str, Any]:
    return {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Effect": "Allow",
                "Principal": {
                    "AWS": f"arn:aws:iam::{platform_account_id}:root",
                },
                "Action": "sts:AssumeRole",
                "Condition": {
                    "StringEquals": {"sts:ExternalId": external_id},
                },
            }
        ],
    }


def build_permissions_policy_template(
    *,
    customer_account_id: str,
    log_group_name: str,
) -> dict[str, Any]:
    resource = (
        f"arn:aws:logs:*:{customer_account_id}:log-group:{log_group_name}:*"
    )
    return {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Effect": "Allow",
                "Action": [
                    "logs:DescribeLogGroups",
                    "logs:DescribeLogStreams",
                    "logs:FilterLogEvents",
                    "logs:StartQuery",
                    "logs:GetQueryResults",
                ],
                "Resource": resource,
            }
        ],
    }


def build_instructions_markdown(
    *,
    platform_account_id: str,
    external_id: str,
    log_group_name: str | None,
) -> str:
    log_group_line = (
        f"`{log_group_name}`" if log_group_name else "your CloudWatch log group"
    )
    return (
        "## Connect Backtrace to your AWS account\n\n"
        f"1. In your AWS account, create an IAM role (e.g. `BacktraceLogsReadRole`).\n"
        f"2. Set the **trust policy** to allow the Backtrace platform account "
        f"`{platform_account_id}` to assume the role with external ID `{external_id}`.\n"
        f"3. Attach a policy that allows CloudWatch Logs read access on {log_group_line}.\n"
        f"4. Enter the role ARN, region, and log group in this onboarding form.\n"
        f"5. Run **Test connection** to verify access.\n"
        f"6. Configure error detection filters and click **Activate monitoring**.\n"
    )


class OnboardingService:
    def __init__(self, session: AsyncSession) -> None:
        self._session = session
        self._users = UserRepository(session)
        self._aws = UserAwsConnectionRepository(session)
        self._detection = UserDetectionConfigRepository(session)

    async def get_status(
        self,
        user: User,
    ) -> dict[str, Any]:
        aws_connection = await self._aws.get(user.id)
        detection_config = await self._detection.get(user.id)
        steps = compute_steps(user, aws_connection, detection_config)
        return {
            "status": user.status,
            "steps": {
                "aws_connection_saved": steps.aws_connection_saved,
                "aws_connection_verified": steps.aws_connection_verified,
                "detection_config_saved": steps.detection_config_saved,
                "monitoring_active": steps.monitoring_active,
            },
            "aws_connection": aws_connection_to_api(aws_connection),
            "detection_config": detection_config_to_api(detection_config),
        }

    async def build_aws_guide(self, user: User) -> dict[str, Any]:
        aws_connection = await self._aws.get(user.id)
        customer_account_id = "CUSTOMER_ACCOUNT_ID"
        log_group_name: str | None = None
        if aws_connection and aws_connection.role_arn:
            parsed = parse_role_account_id(aws_connection.role_arn)
            if parsed:
                customer_account_id = parsed
            log_group_name = aws_connection.log_group_name

        platform_id = settings.platform_aws_account_id
        permissions = build_permissions_policy_template(
            customer_account_id=customer_account_id,
            log_group_name=log_group_name or "/ecs/your-log-group",
        )
        return {
            "platform_aws_account_id": platform_id,
            "external_id": user.external_id,
            "trust_policy_template": build_trust_policy_template(
                platform_account_id=platform_id,
                external_id=user.external_id,
            ),
            "permissions_policy_template": permissions,
            "instructions_markdown": build_instructions_markdown(
                platform_account_id=platform_id,
                external_id=user.external_id,
                log_group_name=log_group_name,
            ),
        }

    async def save_aws_connection(
        self,
        user_id: UUID,
        *,
        aws_region: str,
        log_group_name: str,
        role_arn: str,
    ) -> dict[str, Any]:
        row = await self._aws.upsert(
            user_id,
            aws_region=aws_region.strip(),
            log_group_name=log_group_name.strip(),
            role_arn=role_arn.strip(),
        )
        return aws_connection_to_api(row) or {}

    async def get_detection_config(self, user_id: UUID) -> dict[str, Any]:
        row = await self._detection.get_or_create(user_id)
        return detection_config_to_api(row)

    async def patch_detection_config(
        self,
        user_id: UUID,
        *,
        error_filter_field: str | None = None,
        error_filter_values: list[str] | None = None,
        lifecycle_window_minutes: int | None = None,
        anchor_patterns: list[str] | None = None,
        custom_grok_patterns: list[str] | None = None,
        actionable_severities: list[str] | None = None,
        clear_lifecycle_window: bool = False,
        clear_actionable_severities: bool = False,
    ) -> dict[str, Any]:
        row = await self._detection.update(
            user_id,
            error_filter_field=error_filter_field,
            error_filter_values=error_filter_values,
            lifecycle_window_minutes=lifecycle_window_minutes,
            anchor_patterns=anchor_patterns,
            custom_grok_patterns=custom_grok_patterns,
            actionable_severities=actionable_severities,
            clear_lifecycle_window=clear_lifecycle_window,
            clear_actionable_severities=clear_actionable_severities,
        )
        return detection_config_to_api(row)

    async def activate(self, user: User) -> tuple[User | None, list[str]]:
        aws_connection = await self._aws.get(user.id)
        detection_config = await self._detection.get(user.id)
        missing = activation_missing_steps(user, aws_connection, detection_config)
        if missing:
            return None, missing
        updated = await self._users.update_status(user.id, UserStatus.ACTIVE)
        return updated, []

    async def deactivate(self, user_id: UUID) -> User | None:
        return await self._users.update_status(user_id, UserStatus.PENDING_SETUP)

