router = APIRouter(prefix="/onboarding", tags=["onboarding"])


class AwsConnectionInput(BaseModel):
    aws_region: str = Field(min_length=1, max_length=32)
    log_group_name: str = Field(min_length=2, max_length=512)
    role_arn: str = Field(min_length=20, max_length=512)


class DetectionConfigPatch(BaseModel):
    error_filter_field: str | None = Field(default=None, max_length=64)
    error_filter_values: list[str] | None = None
    lifecycle_window_minutes: int | None = Field(default=None, ge=1, le=1440)
    anchor_patterns: list[str] | None = None
    custom_grok_patterns: list[str] | None = None
    actionable_severities: list[str] | None = None


class ConnectionTestResponse(BaseModel):
    ok: bool
    message: str
    error_code: str | None = None
    verified_at: datetime | None = None
    sample_event_count: int = 0


class ActivateResponse(BaseModel):
    status: str
    message: str


class DeactivateResponse(BaseModel):
    status: str


class ActivateErrorDetail(BaseModel):
    detail: str
    missing_steps: list[str]


def _get_onboarding_service(session: AsyncSession = Depends(get_db_session)) -> OnboardingService:
    return OnboardingService(session)


@router.get("/status")
async def onboarding_status(
    user: User = Depends(get_current_user),
    service: OnboardingService = Depends(_get_onboarding_service),
) -> dict[str, Any]:
    return await service.get_status(user)


@router.get("/aws/guide")
async def aws_setup_guide(
    user: User = Depends(get_current_user),
    service: OnboardingService = Depends(_get_onboarding_service),
) -> dict[str, Any]:
    return await service.build_aws_guide(user)


@router.put("/aws")
async def save_aws_connection(
    body: AwsConnectionInput,
    user: User = Depends(get_current_user),
    service: OnboardingService = Depends(_get_onboarding_service),
) -> dict[str, Any]:
    try:
        validate_aws_connection_input(
            aws_region=body.aws_region,
            log_group_name=body.log_group_name,
            role_arn=body.role_arn,
        )
    except ValueError as exc:
        raise HTTPException(
            status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,
            detail=str(exc),
        ) from exc
    return await service.save_aws_connection(
        user.id,
        aws_region=body.aws_region,
        log_group_name=body.log_group_name,
        role_arn=body.role_arn,
    )


@router.post("/aws/test-connection", response_model=ConnectionTestResponse)
async def test_aws_connection(
    user: User = Depends(get_current_user),
    session: AsyncSession = Depends(get_db_session),
) -> ConnectionTestResponse:
    aws_repo = UserAwsConnectionRepository(session)
    conn = await aws_repo.get(user.id)
    if conn is None or not (conn.aws_region and conn.log_group_name and conn.role_arn):
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail="Save AWS connection settings before testing",
        )

    result = await test_cloudwatch_connection(
        role_arn=conn.role_arn,
        external_id=user.external_id,
        aws_region=conn.aws_region,
        log_group_name=conn.log_group_name,
    )
    await aws_repo.record_connection_test(
        user.id,
        ok=result.ok,
        error_message=None if result.ok else result.message,
    )
    row = await aws_repo.get(user.id)
    verified_at = row.connection_verified_at if row else None

    return ConnectionTestResponse(
        ok=result.ok,
        message=result.message,
        error_code=result.error_code,
        verified_at=verified_at,
        sample_event_count=result.sample_event_count,
    )


@router.get("/detection-config")
async def get_detection_config(
    user: User = Depends(get_current_user),
    service: OnboardingService = Depends(_get_onboarding_service),
) -> dict[str, Any]:
    return await service.get_detection_config(user.id)


@router.patch("/detection-config")
async def patch_detection_config(
    body: DetectionConfigPatch,
    user: User = Depends(get_current_user),
    service: OnboardingService = Depends(_get_onboarding_service),
) -> dict[str, Any]:
    if body.error_filter_values is not None and not body.error_filter_values:
        raise HTTPException(
            status_code=status.HTTP_422_UNPROCESSABLE_ENTITY,
            detail="error_filter_values must not be empty",
        )
    return await service.patch_detection_config(
        user.id,
        error_filter_field=body.error_filter_field,
        error_filter_values=body.error_filter_values,
        lifecycle_window_minutes=body.lifecycle_window_minutes,
        anchor_patterns=body.anchor_patterns,
        custom_grok_patterns=body.custom_grok_patterns,
        actionable_severities=body.actionable_severities,
    )


@router.post("/activate", response_model=ActivateResponse)
async def activate_monitoring(
    user: User = Depends(get_current_user),
    service: OnboardingService = Depends(_get_onboarding_service),
) -> ActivateResponse:
    updated, missing = await service.activate(user)
    if updated is None:
        raise HTTPException(
            status_code=status.HTTP_409_CONFLICT,
            detail={
                "detail": "Onboarding prerequisites not met",
                "missing_steps": missing,
            },
        )
    return ActivateResponse(
        status=updated.status,
        message="Monitoring enabled. First poll within 60 seconds.",
    )


@router.post("/deactivate", response_model=DeactivateResponse)
async def deactivate_monitoring(
    user: User = Depends(get_current_user),
    service: OnboardingService = Depends(_get_onboarding_service),
) -> DeactivateResponse:
    updated = await service.deactivate(user.id)
    if updated is None:
        raise HTTPException(status_code=status.HTTP_404_NOT_FOUND, detail="User not found")
    return DeactivateResponse(status=updated.status)

