/**
 * Backtrace API types for frontend apps.
 * Base URL: process.env.VITE_API_URL or NEXT_PUBLIC_API_URL (default http://localhost:8000)
 *
 * All authenticated requests must use credentials: 'include'.
 */

export type UserStatus = 'pending_setup' | 'active' | 'suspended';

export type IncidentStatus = 'open' | 'closed';

export type IncidentListFilter = 'open' | 'closed' | 'all';

export type MonitoringHealthStatus =
  | 'healthy'
  | 'stale'
  | 'degraded'
  | 'setup_required'
  | 'pending'
  | 'inactive';

export type LifecycleStatus = 'complete' | 'single_event' | 'empty';

export type CorrelationMethod =
  | 'request_id'
  | 'trace_id'
  | 'session_id'
  | 'span_id_endpoint'
  | 'endpoint_service'
  | 'host_pod_container'
  | 'log_stream'
  | 'none';

export type CorrelationConfidence =
  | 'exact_request_id'
  | 'trace_correlated'
  | 'request_shape_match'
  | 'stream_fallback'
  | 'partial'
  | 'no_request_id';

/** FastAPI error body */
export interface ApiError {
  detail: string | ApiErrorDetail;
}

export interface ApiErrorDetail {
  detail: string;
  missing_steps?: string[];
}

// --- Auth ---

export interface AuthMeResponse {
  id: string;
  email: string;
  name: string | null;
  status: UserStatus;
  created_at: string;
  onboarding_complete: boolean;
}

// --- Onboarding ---

export interface OnboardingSteps {
  aws_connection_saved: boolean;
  aws_connection_verified: boolean;
  detection_config_saved: boolean;
  monitoring_active: boolean;
}

export interface AwsConnection {
  aws_region: string;
  log_group_name: string;
  role_arn: string;
  connection_verified_at: string | null;
  last_connection_error: string | null;
  last_connection_test_at: string | null;
}

export interface DetectionConfig {
  error_filter_field: string;
  error_filter_values: string[];
