function queryString(params: Record<string, string | number | undefined>): string {
  const q = new URLSearchParams();
  for (const [k, v] of Object.entries(params)) {
    if (v !== undefined && v !== '') q.set(k, String(v));
  }
  const s = q.toString();
  return s ? `?${s}` : '';
}

export const incidents = {
  list: (params: IncidentListParams = {}) =>
    request<IncidentListResponse>(
      `/incidents${queryString({
        status: params.status,
        since: params.since,
        limit: params.limit,
        offset: params.offset,
      })}`
    ),
  get: (id: string) => request<IncidentDetail>(`/incidents/${id}`),
  occurrences: (id: string, params: OccurrenceListParams = {}) =>
    request<OccurrenceListResponse>(
      `/incidents/${id}/occurrences${queryString({
        limit: params.limit,
        offset: params.offset,
      })}`
    ),
  patch: (id: string, body: IncidentPatchRequest) =>
    request<IncidentListResponse['items'][0]>(`/incidents/${id}`, {
      method: 'PATCH',
      body: JSON.stringify(body),
    }),
};

